'use strict';

const express = require('express');
const fs = require('fs');
const path = require('path');

const app = express();
const PORT = process.env.PORT || 3001;
const API_KEY = process.env.API_KEY || 'mock-api-key-for-testing';

app.use(express.json());

// ─── Load databases ────────────────────────────────────────────────────────────

function loadDb(filename) {
  const legacyPath = path.join(__dirname, filename);
  const dataPath = path.join(__dirname, 'data', filename);
  const filePath = fs.existsSync(dataPath) ? dataPath : legacyPath;
  return JSON.parse(fs.readFileSync(filePath, 'utf8'));
}

const universityMembers = loadDb('university_members.json');
const governmentRecords = loadDb('government_records.json');
const employerRecords = loadDb('employer_records.json');

// Keep legacy members.json working if present
let legacyMembers = [];
try {
  legacyMembers = loadDb('members.json');
} catch (_) {
  legacyMembers = universityMembers;
}

// ─── Middleware ────────────────────────────────────────────────────────────────

function authenticate(req, res, next) {
  const key =
    req.headers['x-api-key'] ||
    req.headers['authorization']?.replace('Bearer ', '');
  if (!key || key !== API_KEY) {
    return res.status(401).json({ error: 'Unauthorized: invalid or missing API key' });
  }
  next();
}

function requestLogger(req, res, next) {
  console.log(`[${new Date().toISOString()}] ${req.method} ${req.path}`, req.body || '');
  next();
}

app.use(requestLogger);

// ─── Helpers ──────────────────────────────────────────────────────────────────

function findByIdentifier(db, identifier) {
  if (!identifier) return null;
  return db.find(
    (r) =>
      r.national_id === identifier ||
      r.membership_number === identifier ||
      r.employee_id === identifier ||
      r.record_number === identifier ||
      r.email === identifier
  ) || null;
}

