   126→export function startNotificationPolling(): void {
   127→  if (pollTimer) return;
   128→
   129→  fetchNotifications().catch(() => {});
   130→
   131→  pollTimer = setInterval(() => {
   132→    fetchNotifications().catch(() => {});
   133→  }, POLL_INTERVAL_MS);
   134→
   135→  appStateSubscription = AppState.addEventListener('change', (state: AppStateStatus) => {
   136→    if (state === 'active') {
