   109→      return { success: true, data: { shareUrl: res.share_url, qrToken: res.share_token, expiresAt: '' }, timestamp: new Date().toISOString() };
   110→    } catch (e) {
   111→      return { success: false, message: e instanceof Error ? e.message : 'Failed', timestamp: new Date().toISOString() };
   112→    }
   113→  },
   114→};
